#include <bits/stdc++.h>
#define int long long
using namespace std;
const int N = 1e6 + 5;
const int mod = 1e9 + 7;
const int INF = 1e18;
int head[N], ver[2 * N], net[2 * N], edge[2 * N], tot;
int n, flag;
int ans1 = 1, ans2 = INF, f[N][105], R;
void add (int a, int b, int c) {
	net[++tot] = head[a];
	head[a] = tot;
	ver[tot] = b;
	edge[tot] = c;
	return;
}
void dfs (int x, int fa, int op) {
	if (op == 1) {
		ans1 = (ans1 * R) % mod;
	}
	else if (op == 0) {
		ans1 = (ans1 * (R - 1)) % mod;
	}
	for (int i = head[x]; i; i = net[i]) {
		int v = ver[i];
		if (v == fa) {
			continue;
		}
		dfs (v, x, edge[i]);
	}
	return;
}
void dfs2 (int x, int fa) {
	for (int i = 1; i <= R; i++) {
		f[x][i] = i;
	}
	for (int i = head[x]; i; i = net[i]) {
		int v = ver[i];
		if (v == fa) {
			continue;
		}
		dfs2 (v, x);
		if (edge[i] == 0) {
			int m1 = INF, m2 = m1;
			int id = 0;
			for (int i = 1; i <= R; i++) {
				if (f[v][i] < m1) {
					m2 = m1;
					m1 = f[v][i];
					id = i;
				} else if (f[v][i] < m2) {
					m2 = f[v][i];
				}
			} 
			for (int i = 1; i <= R; i++) {
				if (i == id) {
					f[x][i] += m2;
				} else {
					f[x][i] += m1;
				}
			}
		} else if (edge[i] == 1) {
			int mi = INF;
			for (int i = 1; i <= R; i++) {
				mi = min (mi, f[v][i]);
			}
			for (int i = 1; i <= R; i++) {
				f[x][i] += mi;
			}
		} else {
			for (int i = 1; i <= R; i++) {
				f[x][i] += f[v][i];
			}
		}
	}
	return;
}
signed main() {
	cin >> n >> R;
	for (int i = 1; i < n; i++) {
		int a, b, c;
		cin >> a >> b >> c;
		add (a, b, c);
		add (b, a, c);
		if (!c) {
			flag = 1;
		}
	}
	if (flag && R == 1) {
		cout << "0 0";
		return 0;
	}
	dfs (1, 0, 1);
	dfs2 (1, 0);
	for (int i = 1; i <= R; i++) {
		ans2 = min (ans2, f[1][i]);
	}
	cout << ans1 << ' ' << ans2;
	return 0;
}
